entry.content:
1. 环境准备 Win8x64以上PC一台,内存4G以上,需要支持CPU虚拟化 VS2013以上,我使用的VS2015RC 爱应用SDK 2. 下载解压爱应用SDK,找到对应平台的支付和登录SDK登录:51Wp.AccountSdk.dll支付:51Wp.PaymentSdk.dll 3. 编写SDK管理脚本WpPlatform.cs1234567891011121314151617181920212223242526272829303132333435363738394041424344454647using UnityEngine;using System.Collections;public class WpPlatform &#123;public static WpPlatform instance = new WpPlatform();#region 登录//登录委托public delegate void CallBack ();public CallBack initLogin;public void GgotoAYYLogin()&#123;if(initLogin != null)&#123;initLogin();&#125;&#125;//登录回调public delegate void CallBackStr(string gameId,string supplyId);public CallBackStr logincallBack;public void LoginResult(bool isSucc,string userName,string userId)&#123;if(logincallBack != null &amp;&amp; isSucc)&#123;logincallBack(userName,userId);&#125;&#125;#endregion#region 支付//开启支付public delegate void GoTopay( string playerId,string goodsId,string goodsName,int count,string unitPrice,string finalPrice);public GoTopay goToPay;public void GotoAYYPay(string playerId,string goodsId,string goodsName,int count,string unitPrice,string finalPrice)&#123;if(goToPay != null)&#123;goToPay(playerId,goodsId,goodsName,count,unitPrice,finalPrice);&#125;&#125;//支付结果回调public delegate void PayCallBack(bool isSucc);public PayCallBack payCallBack;public void PayResult(bool isSucc,string orderId,string goodsId,string goodsName,string goodsPrice,string PlayerId,string msg)&#123;if(payCallBack != null)&#123;payCallBack(isSucc);&#125;&#125;#endregion &#125; 4. 编写游戏内逻辑脚本,将登录结果和支付结果的回调注册进去。5. 构建WP工程,使用Win8以上的Win电脑VS2013以上打开工程,添加对SDK的引用。6. 打开WMAppManifest.xml. 应用程序UI—配置iCO、应用名称、图块资源. 功能—分别添加ID_CAP_IDENTITY_USER、ID_CAP_MEDIALIB_PHOTO、ID_CAP_WEBBROWSERCOMPONENT三个功能. 打包—此时并不修改AppID,待应用上传后商店会再次签名生成AppID,之后再复制商店的AppID填入 7. 打开MainPage.xaml添加LayerRoot12345&lt;Grid x:Name=&quot;LayoutRoot&quot;&gt;&lt;!--LayoutRoot is the root grid where all page content is placed--&gt;&lt;DrawingSurfaceBackgroundGrid x:Name=&quot;DrawingSurfaceBackground&quot; Loaded=&quot;DrawingSurfaceBackground_Loaded&quot;&gt;&lt;/DrawingSurfaceBackgroundGrid&gt;&lt;/Grid&gt; 8. 打开AppXaml.cs在App的构造函数结尾添加SDK初始化方法12//初始化新峰支付Payment.Initialize(SDKConfig.SupplyId, SDKConfig.GameId, Xapcn.PaymentSdk.Common.LanguageType.ZH, RootFrame); 9. 打开MainPage.xaml.cs,添加SDK业务逻辑123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119//SDK 配置public static class SDKConfig&#123;//游戏IDpublic static string GameId = &quot;xxx&quot;;//厂商IDpublic static string SupplyId = &quot;xxx&quot;;//支付回调地址public static string PayURL = &quot;xxx&quot;;&#125;#region sdk接入//次方法为WP中Unity入口private void Unity_Loaded()&#123;SetupGeolocator();try&#123;long result =(long)DeviceExtendedProperties.GetValue(&quot;ApplicationWorkingSetLimit&quot;);UnityEngine.Debug.Log(result);&#125;catch (ArgumentOutOfRangeException)&#123;&#125;wpp = WpPlatform.GetInstance();wpp.initLogin = InitSDK;wpp.goToPay = GoToPay;InitSDK();&#125;void InitSDK()&#123;Dispatcher.BeginInvoke(() =&gt;&#123;//此处初始化登录Account.AccountInit(SDKConfig.GameId, SDKConfig.SupplyId, LayoutRoot, this, true);//此处注册登录结果回调事件Account.LoginStateCallback += Account_LoginStateCallback;//此处注册登录框被用户手动关闭事件Account.LoginCloseCallback += Account_LoginCloseCallback;&#125;);&#125;void Account_LoginCloseCallback()&#123;// MessageBox.Show(&quot;登入未完成，用户手动关闭了登入框&quot;);UnityEngine.Application.Quit();&#125;/// &lt;summary&gt;/// 登入结果返回事件./// &lt;/summary&gt;/// &lt;param name=&quot;loginState&quot;&gt;State of the login.&lt;/param&gt;void Account_LoginStateCallback(_51Wp.AccountSdk.Net.Datas.LoginStateData loginState)&#123;if (loginState.ReturnCode == &quot;0&quot;)&#123;//此处增加防伪造登录校验string strUrl = &quot;http://www.51wp.com/winphone/index.php?s=/oauth2/checkAccount&amp;uid=&#123;0&#125;&amp;datetime=&#123;1&#125;&amp;uniqueid=&#123;2&#125;&quot;;var token = loginState.Token;var times = loginState.LoginTime;var uid = loginState.UserId;string urlPath = string.Format(strUrl, new string[] &#123; uid, times, token &#125;);var client = new WebClient();client.DownloadStringAsync(new Uri(urlPath, UriKind.Absolute));client.DownloadStringCompleted += (ss, ee) =&gt;&#123;if (ee.Error == null)&#123;if (ee.Result.ToString() == &quot;0&quot;)//0为正常登录，非0为伪造登录&#123;// MessageBox.Show(&quot;登录成功，玩家信息：username=&quot; + loginState.UserName + &quot;,userId=&quot; + loginState.UserId);String aa = loginState.UserName;String bb = loginState.UserId;WpPlatform.GetInstance().LoginResult(true, aa, bb);&#125;else&#123;// MessageBox.Show(&quot;登录失败，为伪造登录！&quot;);WpPlatform.GetInstance().LoginResult(false, &quot;&quot;, &quot;&quot;);&#125;&#125;&#125;;&#125;else&#123;WpPlatform.GetInstance().LoginResult(false, &quot;&quot;, &quot;&quot;);&#125;&#125;private void GoToPay(string playerId, string goodsId, string goodsName, int count, string unitPrice, string finalPrice)&#123;string ss = (&quot;
&quot; + goodsId + &quot;
&quot; + goodsName + &quot;
&quot; + count + unitPrice + &quot;
&quot; + finalPrice + &quot;
&quot;);UnityEngine.Debug.Log(ss);Dispatcher.BeginInvoke(() =&gt;&#123;//用户类型 强制注册用户PaymentType PlayerType = PaymentType.RegistedUser;//此处选择浏览器类型，对于部分消耗资源较大的游戏建议使用PayBehaviorType.OutIEPay外置浏览器PayBehaviorType WebType = PayBehaviorType.WebPayCentre;this.IsEnabled = false;Payment.CreateOrder(PlayerType, playerId, goodsId, goodsName, count, double.Parse(unitPrice), double.Parse(finalPrice), SDKConfig.PayURL);try&#123;//开始支付Payment.Pay(WebType,(er, code) =&gt;&#123;//处理商品的发送逻辑//只有当errorCode=0时为支付成功，否则为支付失败if (code.Result.ErrorCode == 0)&#123;wpp.payCallBack(true);UnityEngine.Debug.Log(&quot;订单号: &quot; + code.Result.OrderId + &quot;
商品编号: &quot; + code.Result.GoodsId + &quot;
商品名称: &quot; + code.Result.GoodsName + &quot;
商品价格: &quot; + code.Result.GoodsPrice + &quot;
玩家帐号: &quot; + code.Result.PlayerId + &quot;
游戏唯一编号: &quot; + code.Result.GameId + &quot; 
订单状态：支付成功，可以发放道具商品了&quot;);// MessageBox.Show(&quot;订单号: &quot; + code.Result.OrderId + &quot;
商品编号: &quot; + code.Result.GoodsId + &quot;
商品名称: &quot; + code.Result.GoodsName + &quot;
商品价格: &quot; + code.Result.GoodsPrice + &quot;
玩家帐号: &quot; + code.Result.PlayerId + &quot;
游戏唯一编号: &quot; + code.Result.GameId + &quot; 
订单状态：支付成功，可以发放道具商品了&quot;, &quot;支付成功&quot;, MessageBoxButton.OK);&#125;else&#123;wpp.payCallBack(false);UnityEngine.Debug.Log(&quot;订单号: &quot; + code.Result.OrderId + &quot;
商品编号: &quot; + code.Result.GoodsId + &quot;
商品名称: &quot; + code.Result.GoodsName + &quot;
商品价格: &quot; + code.Result.GoodsPrice + &quot;
玩家帐号: &quot; + code.Result.PlayerId + &quot;
游戏唯一编号: &quot; + code.Result.GameId + &quot; 
订单状态：支付失败&quot;);&#125;GC.Collect();//释放资源&#125;);this.IsEnabled = true;&#125;catch (Exception ex)&#123;Dispatcher.BeginInvoke(() =&gt;&#123;this.IsEnabled = true;MessageBox.Show(ex.Message);UnityEngine.Debug.Log(ex.Message);wpp.payCallBack(false);&#125;);&#125;&#125;);&#125;#endregion 10. 接入手机直接Run就行了,前提是手机为开发机。如需要部署XAP文件,则使用VS2015配套的Windows Phone Application Deployment 8.1选择安装包,点击部署即可.如果手机未开启开发者模式,打开VS2015配套的Windows Phone Developer Registration 8.1输入开发者账号，点击解锁等待一下即可。需要注意的是,即使是开发者也只能在开发机上同时部署10个开发者应用(使用爱应用安装的破解软件也属于开发者应用),超过卸载多余的软件即可继续部署。 07-02添加新爱应用统计添加对XAPCNStatistics.dll的引用在App.xaml.cs的Application_Launching方法中添加如下方法,初始化爱应用统计12345private void Application_Launching(object sender, LaunchingEventArgs e)&#123; XAPCNStatistics.InitStatistics init = new XAPCNStatistics.InitStatistics(); init.Action(SDKConfig.GameId);&#125;
